/**
 * Validates that a value is a positive integer.
 *
 * @param name - The field name used in the error message.
 * @param n - The value to validate.
 *
 * @example
 * ```ts
 * const count = validatePositiveInteger('maxRetries', opts.maxRetries);
 * ```
 */
export function validatePositiveInteger(name: string, n: unknown): number {
  if (typeof n !== 'number' || !Number.isInteger(n) || n < 0) {
    throw new AnthropicError(`${name} must be a non-negative integer`);
  }
  return n;
}
